        dataArr:[],
        queData:{},//评分数据
        currentFeedBackIndex: "1",//当前反馈类型key
        currentUserFunctionIndex:"1",//当前功能类型key
        init:function ( pageType) { //pageType非必填
            var _this = this;
            //参数校验
            if(!pageType){
                pageType = this.getPageType().type;
            }
            if(this.config.pageType.indexOf(pageType) == -1){
                return;
            }
            token = this.getCookies("token");
            //jQuery是否加载
            if(!window.jQuery){
                this.renderJs(function () {
                    _this.getPopup(pageType);
                })
                return;
            }
            this.getPopup(pageType);
        },
        //获取当前页面类型
        getPageType:function () {
            var url = location.pathname;
            if(url == "/"){
                return {type:"po_home",name:"官网首页"}
            }
            if(["/history","/diagrams","/colla","/fav","/trash","/template_create"].indexOf(url) !== -1){
                return {type:"personal_file",name:"个人文件页"}
            }
            if(["/template","/diagrams/new"].indexOf(url) !== -1 || url.indexOf("/template/") === 0){
                return {type:"template_home",name:"模板首页"}
            }
            if(url == "/upgrade"){
                return {type:"price",name:"价格页"}
            }
            if(url.indexOf("/view/") !== -1 && url.indexOf("/link") ==-1){
                return {type:"file_preview",name:"文件预览页"}
            }
            if(url.indexOf("/preview/") !== -1){
                return {type:"template_preview",name:"模板预览页"}
            }
            if(url.indexOf("/popular") !== -1){
                return {type:"recommend",name:"推荐页"}
            }
            if(url.indexOf("/view/link") !== -1){
                return {type:"file_share",name:"文件分享页"}
            }
           
            return ''
        },
        //弹窗接口请求
        getPopup:function ( pageType) {

            var _this = this;
            //腾讯会议、终身会员屏蔽弹窗
            if(navigator.userAgent.indexOf("app/tencent_wemeet") > -1 || this.isMobile()) {
                // j检测更新日志
                //_this.showNewFunction(pageType);
                return;
            }

            var data = {
                pageType: pageType,
            }
            $.ajax({
                url: "/api/personal/universal/nps/get/config",
                type:"get",
                data:data,
                beforeSend: function (xhr) {
                    xhr.setRequestHeader('token', token);
                },
                success: function(res){
                    if(res.data && res.data.configId){
                        if(_this.queData){
                            _this.queData.configId = res.data.configId
                            _this.queData.title = res.data.title
                            _this.queData.pageStaySecond = res.data.pageStaySecond || 10;
                            _this.queData.userTypes = res.data.userTypes;
                            _this.queData.pageType = _this.getPageType().type;
                            if(_this.queData.userTypes.indexOf("vip_user") > -1){
                                _this.queData.userTypes = "vip_user";
                            }else if(_this.queData.userTypes.indexOf("vip_already_expire_user") > -1){
                                _this.queData.userTypes = "vip_already_expire_user";
                            }else if(_this.queData.userTypes.indexOf("free_user") > -1){
                                _this.queData.userTypes = "free_user";
                            }else{
                                _this.queData.userTypes = "browse_user";
                            }
                        }
                        // setTimeout(() => {
                           nps.showDlg() 
                            //展示埋点上报
                            window.buried_point_fn && buried_point_fn('nomal', 'NPS_show', {
                                'NPS标题': _this.queData.title,
                                '当前页面': _this.getPageType().name,
                                '弹窗名称': "NPS评分弹窗",
                                // '触发位置': isById ? '广告位配置' : '主动弹出',
                            })
                        // }, _this.queData.pageStaySecond*1000);
                        
                    }
                    
                    // if(res.data && res.data.length){
                    //     if (Object.prototype.toString.call([res.data]) === "[object Array]") {
                    //         _this.dataArr = res.data;
                    //     }
                    // }else {
                    //     // j检测更新日志
                    //     _this.showNewFunction(pageType);
                    // }
                },
                error:function(res){
                    console.log(res)
                }
            });

            
        },
