        //模块
        module:{
        },
        renderJs:function (callback){
            var doc = document, url = '/static/js/jquery.js';
            var js = doc.createElement("script");
            js.setAttribute("type", "text/javascript");
            js.setAttribute("src", url);
            js.setAttribute("charset", "UTF-8");
            doc.head.appendChild(js);
            js.onload = function(){
                callback && callback()
            }
        },
        getCookies: function(c_name){
            if(document.cookie.length > 0){
                var c_start = document.cookie.indexOf(c_name + "=");
                if(c_start != -1){
                    c_start = c_start + c_name.length + 1;
                    var c_end = document.cookie.indexOf(";", c_start);
                    if(c_end == -1){
                        c_end=document.cookie.length;
                    }
                    return unescape(document.cookie.substring(c_start, c_end));
                }
            }
            return ""
        },
        //手机端价格页屏蔽关闭按钮
        isPhoneIgnoreClose:function(){
           if((navigator.userAgent.match(/(iPhone|iPod|Android|ios|iPad)/i) || $('body').width() < 600) && location.href.indexOf("/upgrade")>-1){
              return true;
           }else{
              return false;
           }
            
        },
        //判断是手机端还是pc端
        isMobile:function (){
            if(window.navigator.userAgent.match(/(phone|pad|pod|iPhone|iPod|ios|iPad|Android|Mobile|BlackBerry|IEMobile|MQQBrowser|JUC|Fennec|wOSBrowser|BrowserNG|WebOS|Symbian|Windows Phone)/i)) {
                return true; // 移动端
            }else{
                return false; // PC端
            } 
        },
